<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Service Agreements</h1><p class="text-muted mb-0">Create plain-language agreements and collect signatures online.</p></div></div><div class="row g-4"><div class="col-lg-4"><div class="card shadow-sm"><div class="card-body"><h2 class="h5">New Agreement</h2><form method="post"><?=csrf_field()?><div class="mb-2"><select name="customer_id" class="form-select" required><option value="">Customer</option><?php foreach($customers as $c):?><option value="<?=e($c['id'])?>"><?=e($c['display_name'])?></option><?php endforeach?></select></div><div class="mb-2"><input name="title" class="form-control" placeholder="Residential Service Agreement" required></div><div class="mb-2"><select name="agreement_type" class="form-select"><option>residential</option><option>commercial</option><option>recurring</option><option>maintenance</option><option>custom</option></select></div><div class="row g-2 mb-2"><div class="col"><input type="date" name="effective_date" class="form-control"></div><div class="col"><input type="date" name="expiration_date" class="form-control"></div></div><textarea name="body" rows="8" class="form-control mb-3" placeholder="Leave blank to use the standard terms."></textarea><button class="btn btn-primary w-100">Create Agreement</button></form></div></div></div><div class="col-lg-8"><div class="card shadow-sm"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>Agreement</th><th>Customer</th><th>Status</th><th>Dates</th><th>Actions</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=e($r['agreement_number'])?></strong><div><?=e($r['title'])?></div></td><td><?=e($r['display_name'])?></td><td><span class="badge text-bg-<?=$r['status']==='signed'?'success':'secondary'?>"><?=e($r['status'])?></span></td><td><?=e($r['effective_date'])?> to <?=e($r['expiration_date'])?></td><td><a class="btn btn-sm btn-outline-primary" target="_blank" href="/agreement/<?=e($r['public_token'])?>">Open</a> <form class="d-inline" method="post" action="/portal/agreements/<?=$r['id']?>/send"><?=csrf_field()?><button class="btn btn-sm btn-outline-secondary">Send</button></form> <form class="d-inline" method="post" action="/portal/agreements/<?=$r['id']?>/pdf"><?=csrf_field()?><button class="btn btn-sm btn-outline-dark">PDF</button></form></td></tr><?php endforeach?></tbody></table></div></div></div></div>
